/**
 * Initialize Envelope
 * - Normalizes inbound payloads from Schedule or ExecuteWorkflowTrigger
 * - Ensures ctx exists and survives external node outputs via explicit ctx holds + merges
 * - No env vars; all state flows through json + DataTables
 */

function fnv1a(str) {
  let h = 0x811c9dc5;
  for (let i = 0; i < str.length; i++) {
    h ^= str.charCodeAt(i);
    h = (h >>> 0) * 0x01000193;
  }
  return (h >>> 0).toString(16);
}

const incoming = $json || {};
const now = new Date().toISOString();

// Preserve any ctx already provided
const baseCtx = (incoming.ctx && typeof incoming.ctx === 'object') ? incoming.ctx : {};

const traceSeed = JSON.stringify(incoming).slice(0, 5000) + '::' + now;
const traceId = baseCtx.trace_id || `tvpx_${fnv1a(traceSeed)}`;

const ctx = {
  project_ns: 'TVPX',
  brand_name: 'The Velvet Paradox',
  trace_id: traceId,
  trigger_mode: baseCtx.trigger_mode || (incoming.message ? 'telegram' : 'schedule'),
  route_mode: baseCtx.route_mode || 'crawl',
  run_started_at: now,
  // Optional knobs (safe defaults)
  crawl_profile: baseCtx.crawl_profile || incoming.crawl_profile || 'default',
  max_pages_per_source: Number(baseCtx.max_pages_per_source || incoming.max_pages_per_source || 50),
  max_fragments_per_page: Number(baseCtx.max_fragments_per_page || incoming.max_fragments_per_page || 8),
  max_fragment_chars: Number(baseCtx.max_fragment_chars || incoming.max_fragment_chars || 2200)
};

return [{
  json: {
    ctx,
    input: incoming.input || incoming,
    carry: incoming.carry || {},
    // Telegram payload may exist upstream; keep it but do not rely on it here
    tg: incoming.tg || incoming.message || {}
  }
}];

/**
 * Reattach Context After Get Sources
 * DataTable nodes may output rows without our envelope.
 * We rebuild items as { ctx, sourceRow }.
 */

const incoming = $items('Initialize Envelope')[0].json;
const ctx = incoming.ctx;

return $input.all().map(item => {
  return {
    json: {
      ctx,
      source: item.json,
      carry: incoming.carry || {},
      input: incoming.input || {}
    }
  };
});

/**
 * Build Crawl Run Record
 * Creates crawl_run_id + minimal ledger seed
 */

function fnv1a(str) {
  let h = 0x811c9dc5;
  for (let i = 0; i < str.length; i++) {
    h ^= str.charCodeAt(i);
    h = (h >>> 0) * 0x01000193;
  }
  return (h >>> 0).toString(16);
}

const j = $json;
const ctx = j.ctx;
const source = j.source || {};

const now = new Date().toISOString();
const sourceId = String(source.source_id || source.id || source.dt_row_id || '').trim();
const sourceUrl = String(source.source_url || source.url || '').trim();

if (!sourceId || !sourceUrl) {
  throw new Error(`Missing source_id or source_url. Got source_id='${sourceId}' source_url='${sourceUrl}'`);
}

const crawlRunId = `tvpx_cr_${fnv1a(ctx.trace_id + '::' + sourceId + '::' + now)}`;

return [{
  json: {
    ctx: { ...ctx, crawl_run_id: crawlRunId, source_id: sourceId },
    source,
    crawl_run: {
      crawl_run_id: crawlRunId,
      trace_id: ctx.trace_id,
      source_id: sourceId,
      trigger_mode: ctx.trigger_mode,
      status: 'started',
      started_at: now
    }
  }
}];

function parseJsonSafe(value, fallback) {
  if (value === null || value === undefined || value === '') return fallback;
  if (typeof value === 'object') return value;
  try {
    return JSON.parse(String(value));
  } catch {
    return fallback;
  }
}

const j = $json || {};
const ctx = (j.ctx && typeof j.ctx === 'object') ? j.ctx : {};
const source = (j.source && typeof j.source === 'object') ? j.source : {};

const sourceUrl = String(source.source_url || source.url || '').trim();
if (!sourceUrl) {
  throw new Error('TVPX__10 / Build Apify Request Body: source_url is required.');
}

const actorId = String(source.apify_actor_id || '').trim();
if (!actorId) {
  throw new Error('TVPX__10 / Build Apify Request Body: source.apify_actor_id is required.');
}

const crawlProfile = String(source.crawl_profile || ctx.crawl_profile || 'default').trim();
const maxPages = Math.max(1, Math.min(Number(source.max_pages || ctx.max_pages_per_source || 50), 500));

const apifyInput = {
  startUrls: [{ url: sourceUrl }],
  maxPagesPerCrawl: maxPages,
  includeUrlGlobs: parseJsonSafe(source.include_url_globs, undefined),
  excludeUrlGlobs: parseJsonSafe(source.exclude_url_globs, undefined),
  proxyConfiguration: parseJsonSafe(source.proxy_json, undefined),
  userData: {
    tvpx: {
      trace_id: ctx.trace_id,
      crawl_run_id: ctx.crawl_run_id,
      source_id: ctx.source_id,
      crawl_profile: crawlProfile,
      brand_name: ctx.brand_name
    }
  }
};

return [{
  json: {
    ctx,
    source,
    apify: {
      actor_id: actorId,
      input: apifyInput
    }
  }
}];

const run = $json || {};
const seed = $items('Build Apify Request Body')[0]?.json || {};

const ctx = (seed.ctx && typeof seed.ctx === 'object') ? seed.ctx : {};
const source = (seed.source && typeof seed.source === 'object') ? seed.source : {};

const apifyRunId = String(run.id || run.runId || run.data?.id || '').trim();
const datasetId = String(run.defaultDatasetId || run.data?.defaultDatasetId || run.datasetId || '').trim();

if (!datasetId) {
  throw new Error('TVPX__10 / Normalize Apify Run Output: missing dataset ID from Apify run result.');
}

return [{
  json: {
    ctx,
    source,
    crawl_run_update: {
      crawl_run_id: String(ctx.crawl_run_id || '').trim(),
      apify_run_id: apifyRunId,
      dataset_id: datasetId,
      status: 'running'
    }
  }
}];

/**
 * Normalize Crawl Items
 * Converts dataset items into canonical pages with {url,title,text}
 * Assumes each item includes url/title/text-like fields; adapt mapping here to your actor output.
 */

const base = $items('Normalize Apify Run Output')[0].json;
const ctx = base.ctx;
const source = base.source;

const items = $input.all().map(i => i.json);

// Actor outputs vary; try common patterns.
const pages = items.map((it, idx) => {
  const url = String(it.url || it.pageUrl || it.request?.url || it.requestUrl || '').trim();
  const title = String(it.title || it.pageTitle || it.metadata?.title || '').trim();
  const text = String(it.text || it.content || it.pageText || it.markdown || it.bodyText || '').trim();
  return { url, title, text, index: idx };
}).filter(p => p.url && p.text);

return [{
  json: {
    ctx,
    source,
    crawl_run_id: ctx.crawl_run_id,
    pages
  }
}];

/**
 * Chunk And Clean Text
 * - Retains legacy chunking/payload concept
 * - Produces fragment items shaped for tvpx_text_fragment_bank
 * - Keeps creative goal: extracts "charged" paragraphs, tension words, material cues
 */

function fnv1a(str) {
  let h = 0x811c9dc5;
  for (let i = 0; i < str.length; i++) {
    h ^= str.charCodeAt(i);
    h = (h >>> 0) * 0x01000193;
  }
  return (h >>> 0).toString(16);
}

function clean(s) {
  return String(s || '')
    .replace(/\r/g, '')
    .replace(/[\t ]+/g, ' ')
    .replace(/\n{3,}/g, '\n\n')
    .trim();
}

function splitParagraphs(text) {
  return clean(text)
    .split(/\n\n+/)
    .map(p => clean(p))
    .filter(Boolean);
}

// Simple signal scoring: prioritizes paragraphs likely to produce Velvet Paradox concepts.
const SIGNAL = [
  'pressure','fracture','collapse','repair','restraint','rupture','erosion','threshold','damage','bruise','stain',
  'residue','seep','crack','buckle','warp','misalign','aftermath','tension','constraint','weight','drift','fragile',
  'ritual','memory','identity','veil','shadow','fog','silence','ruin','relic','static','paradox'
];

function scorePara(p) {
  const t = p.toLowerCase();
  let score = 0;
  for (const w of SIGNAL) if (t.includes(w)) score += 1;
  // reward tactile material language
  if (/(stone|plaster|velvet|metal|dust|smoke|haze|wet|rust|cloth|feather|fur|wax|candle)/i.test(p)) score += 2;
  return score;
}

const j = $json;
const ctx = j.ctx;
const source = j.source;
const pages = Array.isArray(j.pages) ? j.pages : [];

const maxFragChars = Number(ctx.max_fragment_chars || 2200);
const maxFragsPerPage = Number(ctx.max_fragments_per_page || 8);

const out = [];

for (const page of pages) {
  const paras = splitParagraphs(page.text);
  // pick best paragraphs first, then pack into fragments
  const ranked = paras
    .map((p, idx) => ({ p, idx, s: scorePara(p) }))
    .sort((a,b) => b.s - a.s);

  const chosen = ranked.slice(0, Math.min(ranked.length, maxFragsPerPage * 3)).map(x => x.p);

  // pack into fragments up to maxFragChars
  let buf = '';
  let chunkIndex = 0;

  for (const p of chosen) {
    const add = buf ? (buf + '\n\n' + p) : p;
    if (add.length > maxFragChars && buf) {
      const cleaned = clean(buf);
      const hash = fnv1a(`${ctx.trace_id}::${ctx.crawl_run_id}::${page.url}::${chunkIndex}::${cleaned}`);
      out.push({
        ctx,
        source,
        fragment: {
          fragment_id: `tvpx_fg_${hash}`,
          crawl_run_id: ctx.crawl_run_id,
          source_id: ctx.source_id,
          page_url: page.url,
          page_title: page.title || '',
          chunk_index: chunkIndex,
          fragment_hash: hash,
          raw_text: buf,
          cleaned_text: cleaned,
          token_estimate: Math.ceil(cleaned.length / 4),
          qa_status: 'clean'
        }
      });
      buf = p;
      chunkIndex += 1;
      if (chunkIndex >= maxFragsPerPage) break;
    } else {
      buf = add;
    }
  }

  if (buf && chunkIndex < maxFragsPerPage) {
    const cleaned = clean(buf);
    const hash = fnv1a(`${ctx.trace_id}::${ctx.crawl_run_id}::${page.url}::${chunkIndex}::${cleaned}`);
    out.push({
      ctx,
      source,
      fragment: {
        fragment_id: `tvpx_fg_${hash}`,
        crawl_run_id: ctx.crawl_run_id,
        source_id: ctx.source_id,
        page_url: page.url,
        page_title: page.title || '',
        chunk_index: chunkIndex,
        fragment_hash: hash,
        raw_text: buf,
        cleaned_text: cleaned,
        token_estimate: Math.ceil(cleaned.length / 4),
        qa_status: 'clean'
      }
    });
  }
}

if (!out.length) {
  // Still proceed, but ledger will mark empty.
  return [{ json: { ctx, source, fragments: [], empty: true } }];
}

return out.map(o => ({ json: o }));

/**
 * Update Crawl Ledger Final
 * - Marks run completed, writes counts
 * - Ensures ctx preserved after fragment upserts
 */

// Source + ctx from earlier stable node
const base = $items('Normalize Apify Run Output')[0].json;
const ctx = base.ctx;
const source = base.source;

const fragmentsInserted = $input.all().length;

return [{
  json: {
    ctx,
    source,
    crawl_run_final: {
      crawl_run_id: ctx.crawl_run_id,
      status: 'completed',
      completed_at: new Date().toISOString(),
      raw_item_count: Number($items('Apify Get Dataset Items').length || 0),
      page_count: Number(($items('Normalize Crawl Items')[0]?.json?.pages || []).length),
      fragment_count: fragmentsInserted
    }
  }
}];
